void addNumber(double x) {
  // Prevent misparsing of consecutive negative signs.
  char prev = getLastChar();
  boolean negativeZero = isNegativeZero(x);
  if (x < 0 && prev == '-') {
    add(" ");
  }

  if ((long) x == x && !negativeZero) {
    long value = (long) x;
    long mantissa = value;
    int exp = 0;
    if (Math.abs(x) >= 100) {
      while (mantissa / 10 * Math.pow(10, exp + 1) == value) {
        mantissa /= 10;
        exp++;
      }
    }
    if (exp > 2) {
      add(Long.toString(mantissa) + "E" + Integer.toString(exp));
    } else {
      add(Long.toString(value));
    }
  } else if (negativeZero) {
    if (prev == '-') {
      add(" ");
    }
    add("-0.0");
  } else if (x == 0 && prev == '-') { // Handle positive and negative zero uniformly
    add(" 0.0");
  } else {
    add(String.valueOf(x));
  }
}

void addNumber(double x) {
  char prev = getLastChar();

  if (Double.isNaN(x)) {
    add("NaN");
    return;
  }

  if (x == Double.POSITIVE_INFINITY) {
    add("Infinity");
    return;
  }

  if (x == Double.NEGATIVE_INFINITY) {
    add("-Infinity");
    return;
  }

  if (isNegativeZero(x)) {
    if (prev == '-') {
      add(" ");
    }
    add("-0.0");
    return;
  }

  if (x < 0 && prev == '-') {
    add(" ");
  }

  if ((long) x == x) {
    long value = (long) x;
    if (Math.abs(value) >= 100) {
      long mantissa = value;
      int exp = 0;
      while ((mantissa / 10) * Math.pow(10, exp + 1) == value) {
        mantissa /= 10;
        exp++;
      }
      if (exp > 2) {
        add(Long.toString(mantissa) + "E" + Integer.toString(exp));
        return;
      }
    }
    add(Long.toString(value));
  } else {
    add(String.valueOf(x));
  }
}
